import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        String[] input = {"eat", "tea", "tan", "ate", "nat", "bat"};
        List<List<String>> result = new Solution().groupAnagrams(input);
        assertEquals(
            List.of(
                List.of("eat", "tea", "ate"),
                List.of("tan", "nat"),
                List.of("bat")
            ),
            result
        );
    }

    @Test
    void empty() {
        List<List<String>> result = new Solution().groupAnagrams(new String[]{});
        assertEquals(List.of(), result);
    }

    @Test
    void singleWord() {
        List<List<String>> result = new Solution().groupAnagrams(new String[]{"hello"});
        assertEquals(List.of(List.of("hello")), result);
    }

    @Test
    void allSameAnagramGroup() {
        // adversarial: every word maps to the same sorted key
        String[] input = {"abc", "bca", "cab", "acb"};
        List<List<String>> result = new Solution().groupAnagrams(input);
        assertEquals(1, result.size());
        assertEquals(List.of("abc", "bca", "cab", "acb"), result.get(0));
    }

    @Test
    void noAnagrams() {
        // each word is in its own group
        String[] input = {"abc", "def", "ghi"};
        List<List<String>> result = new Solution().groupAnagrams(input);
        assertEquals(3, result.size());
        assertEquals(List.of("abc"), result.get(0));
        assertEquals(List.of("def"), result.get(1));
        assertEquals(List.of("ghi"), result.get(2));
    }

    @Test
    void emptyStringWord() {
        // the empty string is its own anagram group
        String[] input = {"", "", "a"};
        List<List<String>> result = new Solution().groupAnagrams(input);
        assertEquals(2, result.size());
        assertEquals(List.of("", ""), result.get(0));
        assertEquals(List.of("a"), result.get(1));
    }

    @Test
    void twoGroupsInterleaved() {
        // groups interleaved in input; outer order must follow first appearance
        String[] input = {"ab", "ba", "cd", "dc", "ab"};
        List<List<String>> result = new Solution().groupAnagrams(input);
        assertEquals(2, result.size());
        assertEquals(List.of("ab", "ba", "ab"), result.get(0));
        assertEquals(List.of("cd", "dc"), result.get(1));
    }
}
